     1тЖТ/**
     2тЖТ * Strategic Heatmap Layer
     3тЖТ *
     4тЖТ * deck.gl WebGL layer for the 12-year strategic PM density view.
     5тЖТ * Renders a heatmap grid where:
     6тЖТ * - Rows = trains
     7тЖТ * - Columns = years
     8тЖТ * - Cell color = PM density (intensity)
     9тЖТ *
    10тЖТ * Used at zoom levels 0-8 (STRATEGIC and TACTICAL_WIDE).
    11тЖТ *
    12тЖТ * @see specs/006-user-interface.md Section 6.3.2
    13тЖТ */
    14тЖТ
    15тЖТimport { ScatterplotLayer, TextLayer } from '@deck.gl/layers';
    16тЖТimport DeckGL from '@deck.gl/react';
    17тЖТimport { OrthographicView } from '@deck.gl/core';
    18тЖТ
    19тЖТimport type { StrategicCanvasData, HeatmapCell } from './types';
    20тЖТ
    21тЖТ// =============================================================================
    22тЖТ// Constants
    23тЖТ// =============================================================================
    24тЖТ
    25тЖТconst CELL_WIDTH = 80;
    26тЖТconst CELL_HEIGHT = 30;
    27тЖТconst CELL_PADDING = 4;
    28тЖТconst LABEL_WIDTH = 100;
    29тЖТconst HEADER_HEIGHT = 40;
    30тЖТ
    31тЖТ/** PM density color scale (light to dark blue) */
    32тЖТconst PM_DENSITY_COLORS: [number, number, number, number][] = [
    33тЖТ  [240, 249, 255, 255], // 0 PMs - very light blue
    34тЖТ  [186, 230, 253, 255], // 1 PM - light blue
    35тЖТ  [125, 211, 252, 255], // 2 PMs
    36тЖТ  [56, 189, 248, 255],  // 3 PMs
    37тЖТ  [14, 165, 233, 255],  // 4 PMs
    38тЖТ  [2, 132, 199, 255],   // 5 PMs
    39тЖТ  [3, 105, 161, 255],   // 6 PMs
    40тЖТ  [7, 89, 133, 255],    // 7+ PMs - dark blue
    41тЖТ];
    42тЖТ
    43тЖТ/** Fleet colors */
    44тЖТconst FLEET_COLORS: Record<string, [number, number, number, number]> = {
    45тЖТ  KS: [14, 165, 233, 255],   // Sky-500
    46тЖТ  ALSTOM: [139, 92, 246, 255], // Violet-500
    47тЖТ  DEFAULT: [100, 116, 139, 255], // Slate-500
    48тЖТ};
    49тЖТ
    50тЖТ// =============================================================================
    51тЖТ// Helper Functions
    52тЖТ// =============================================================================
    53тЖТ
    54тЖТ/**
    55тЖТ * Transform API data into heatmap cells with positions
    56тЖТ */
    57тЖТfunction transformToHeatmapCells(
    58тЖТ  data: StrategicCanvasData,
    59тЖТ  fromYear: number,
    60тЖТ  toYear: number
    61тЖТ): HeatmapCell[] {
    62тЖТ  const cells: HeatmapCell[] = [];
    63тЖТ  const { trains, heatmapData } = data;
    64тЖТ  const maxPmCount = heatmapData.maxPmCount || 1;
    65тЖТ
    66тЖТ  trains.forEach((train, trainIndex) => {
    67тЖТ    for (let year = fromYear; year <= toYear; year++) {
    68тЖТ      const yearIndex = year - fromYear;
    69тЖТ      const yearData = train.years.find((y) => y.year === year);
    70тЖТ
    71тЖТ      const pmCount = yearData?.pmCount ?? 0;
    72тЖТ      const totalHours = yearData?.totalHours ?? 0;
    73тЖТ      const completedCount = yearData?.completedCount ?? 0;
    74тЖТ      const lockedCount = yearData?.lockedCount ?? 0;
    75тЖТ
    76тЖТ      const intensity = Math.min(pmCount / maxPmCount, 1);
    77тЖТ
    78тЖТ      const x = LABEL_WIDTH + yearIndex * (CELL_WIDTH + CELL_PADDING);
    79тЖТ      const y = HEADER_HEIGHT + trainIndex * (CELL_HEIGHT + CELL_PADDING);
    80тЖТ
    81тЖТ      cells.push({
    82тЖТ        trainId: train.trainId,
    83тЖТ        trainNumber: train.trainNumber,
    84тЖТ        trainIndex,
    85тЖТ        year,
    86тЖТ        yearIndex,
    87тЖТ        pmCount,
    88тЖТ        totalHours,
    89тЖТ        completedCount,
    90тЖТ        lockedCount,
    91тЖТ        intensity,
    92тЖТ        position: [x + CELL_WIDTH / 2, y + CELL_HEIGHT / 2],
    93тЖТ      });
    94тЖТ    }
    95тЖТ  });
    96тЖТ
    97тЖТ  return cells;
    98тЖТ}
    99тЖТ
   100тЖТ/**
   101тЖТ * Get color for PM density
   102тЖТ */
   103тЖТfunction getDensityColor(intensity: number): [number, number, number, number] {
   104тЖТ  const index = Math.min(
   105тЖТ    Math.floor(intensity * (PM_DENSITY_COLORS.length - 1)),
   106тЖТ    PM_DENSITY_COLORS.length - 1
   107тЖТ  );
   108тЖТ  return PM_DENSITY_COLORS[index];
   109тЖТ}
   110тЖТ
   111тЖТ// =============================================================================
   112тЖТ// Component Props
   113тЖТ// =============================================================================
   114тЖТ
   115тЖТexport interface StrategicHeatmapProps {
   116тЖТ  data: StrategicCanvasData | null;
   117тЖТ  fromYear: number;
   118тЖТ  toYear: number;
   119тЖТ  width: number | string;
   120тЖТ  height: number | string;
   121тЖТ  onCellHover?: (cell: HeatmapCell | null) => void;
   122тЖТ  onCellClick?: (cell: HeatmapCell) => void;
   123тЖТ  onYearClick?: (year: number) => void;
   124тЖТ}
   125тЖТ
   126тЖТ// =============================================================================
   127тЖТ// Component
   128тЖТ// =============================================================================
   129тЖТ
   130тЖТ/**
   131тЖТ * Strategic Heatmap View
   132тЖТ *
   133тЖТ * Renders a PM density heatmap using deck.gl WebGL layers.
   134тЖТ * Optimized for 60fps rendering of 100+ trains ├Ч 10 years.
   135тЖТ */
   136тЖТexport function StrategicHeatmapLayer({
   137тЖТ  data,
   138тЖТ  fromYear,
   139тЖТ  toYear,
   140тЖТ  width,
   141тЖТ  height,
   142тЖТ  onCellHover,
   143тЖТ  onCellClick,
   144тЖТ  onYearClick,
   145тЖТ}: StrategicHeatmapProps) {
   146тЖТ  if (!data || data.trains.length === 0) {
   147тЖТ    return (
   148тЖТ      <div
   149тЖТ        style={{
   150тЖТ          width,
   151тЖТ          height,
   152тЖТ          display: 'flex',
   153тЖТ          alignItems: 'center',
   154тЖТ          justifyContent: 'center',
   155тЖТ          color: 'var(--pt-text-muted)',
   156тЖТ        }}
   157тЖТ      >
   158тЖТ        No strategic data available
   159тЖТ      </div>
   160тЖТ    );
   161тЖТ  }
   162тЖТ
   163тЖТ  const cells = transformToHeatmapCells(data, fromYear, toYear);
   164тЖТ  const yearCount = toYear - fromYear + 1;
