     1тЖТ/**
     2тЖТ * Tactical Gantt Layer
     3тЖТ *
     4тЖТ * Konva-based Gantt chart layer for tactical PM scheduling (zoom levels 8-12).
     5тЖТ * Renders PM blocks, constraint walls, train labels, and timeline axis.
     6тЖТ *
     7тЖТ * Features:
     8тЖТ * - PM blocks with status-based colors
     9тЖТ * - Compliance window constraint walls
    10тЖТ * - Train labels on the left
    11тЖТ * - Week/day timeline axis at top
    12тЖТ * - Drag-and-drop PM rescheduling (with constraint validation)
    13тЖТ * - Hover tooltips
    14тЖТ *
    15тЖТ * @see specs/006-user-interface.md Section 6.3.3
    16тЖТ */
    17тЖТ
    18тЖТimport { useRef } from 'react';
    19тЖТimport { Stage, Layer, Rect, Text, Line, Group } from 'react-konva';
    20тЖТimport type { KonvaEventObject } from 'konva/lib/Node';
    21тЖТimport type { Stage as StageType } from 'konva/lib/Stage';
    22тЖТ
    23тЖТimport type { PmBlock, ConstraintWall, TacticalCanvasData } from './types';
    24тЖТimport { PM_STATUS_COLORS, CONSTRAINT_COLORS, FLEET_COLORS } from '../../theme/colors';
    25тЖТ
    26тЖТ// =============================================================================
    27тЖТ// Constants
    28тЖТ// =============================================================================
    29тЖТ
    30тЖТ/** Layout constants for the Gantt chart */
    31тЖТconst LAYOUT = {
    32тЖТ  HEADER_HEIGHT: 48,
    33тЖТ  TRAIN_LABEL_WIDTH: 120,
    34тЖТ  ROW_HEIGHT: 40,
    35тЖТ  PM_BLOCK_HEIGHT: 28,
    36тЖТ  PM_BLOCK_MARGIN: 6,
    37тЖТ  DAY_WIDTH: 24,
    38тЖТ  WEEK_WIDTH: 24 * 7,
    39тЖТ  MIN_PM_WIDTH: 20,
    40тЖТ  CONSTRAINT_WALL_WIDTH: 2,
    41тЖТ  GRID_LINE_COLOR: '#e2e8f0',
    42тЖТ  HEADER_BG: '#f8fafc',
    43тЖТ  TRAIN_LABEL_BG: '#ffffff',
    44тЖТ  FONT_FAMILY: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif',
    45тЖТ};
    46тЖТ
    47тЖТ/** PM status to color mapping */
    48тЖТfunction getPmColor(status: string): string {
    49тЖТ  switch (status) {
    50тЖТ    case 'SCHEDULED':
    51тЖТ      return PM_STATUS_COLORS.scheduled;
    52тЖТ    case 'IN_PROGRESS':
    53тЖТ      return PM_STATUS_COLORS.inProgress;
    54тЖТ    case 'COMPLETED':
    55тЖТ      return PM_STATUS_COLORS.completed;
    56тЖТ    case 'CANCELLED':
    57тЖТ      return PM_STATUS_COLORS.cancelled;
    58тЖТ    case 'DEFERRED':
    59тЖТ      return PM_STATUS_COLORS.deferred;
    60тЖТ    default:
    61тЖТ      return PM_STATUS_COLORS.scheduled;
    62тЖТ  }
    63тЖТ}
    64тЖТ
    65тЖТ// =============================================================================
    66тЖТ// Types
    67тЖТ// =============================================================================
    68тЖТ
    69тЖТexport interface TacticalGanttLayerProps {
    70тЖТ  data: TacticalCanvasData | null;
    71тЖТ  trainOrder: string[];
    72тЖТ  fromDate: Date;
    73тЖТ  toDate: Date;
    74тЖТ  width: number;
    75тЖТ  height: number;
    76тЖТ  selectedPmIds: string[];
    77тЖТ  onPmClick?: (pmId: string) => void;
    78тЖТ  onPmHover?: (pm: PmBlock | null) => void;
    79тЖТ  onPmDragStart?: (pmId: string) => void;
    80тЖТ  onPmDragEnd?: (pmId: string, newDate: string) => void;
    81тЖТ  showConstraintWalls?: boolean;
    82тЖТ  showGrid?: boolean;
    83тЖТ}
    84тЖТ
    85тЖТinterface DayData {
    86тЖТ  date: Date;
    87тЖТ  dateStr: string;
    88тЖТ  dayOfWeek: number;
    89тЖТ  isWeekStart: boolean;
    90тЖТ  isToday: boolean;
    91тЖТ}
    92тЖТ
    93тЖТinterface WeekData {
    94тЖТ  weekStart: Date;
    95тЖТ  weekNum: number;
    96тЖТ  daysInWeek: number;
    97тЖТ}
    98тЖТ
    99тЖТ// =============================================================================
   100тЖТ// Pure Utility Functions
   101тЖТ// =============================================================================
   102тЖТ
   103тЖТfunction getDays(fromDate: Date, toDate: Date): DayData[] {
   104тЖТ  const days: DayData[] = [];
   105тЖТ  const current = new Date(fromDate);
   106тЖТ  const today = new Date();
   107тЖТ  today.setHours(0, 0, 0, 0);
   108тЖТ
   109тЖТ  while (current <= toDate) {
   110тЖТ    const dayOfWeek = current.getDay();
   111тЖТ    days.push({
   112тЖТ      date: new Date(current),
   113тЖТ      dateStr: current.toISOString().split('T')[0],
   114тЖТ      dayOfWeek,
   115тЖТ      isWeekStart: dayOfWeek === 0,
   116тЖТ      isToday: current.getTime() === today.getTime(),
   117тЖТ    });
   118тЖТ    current.setDate(current.getDate() + 1);
   119тЖТ  }
   120тЖТ  return days;
   121тЖТ}
   122тЖТ
   123тЖТfunction getWeeks(days: DayData[]): WeekData[] {
   124тЖТ  const weeks: WeekData[] = [];
   125тЖТ  let currentWeek: WeekData | null = null;
   126тЖТ
   127тЖТ  for (const day of days) {
   128тЖТ    if (day.isWeekStart || currentWeek === null) {
   129тЖТ      if (currentWeek) {
   130тЖТ        weeks.push(currentWeek);
   131тЖТ      }
   132тЖТ      const weekNum = getWeekNumber(day.date);
   133тЖТ      currentWeek = { weekStart: day.date, weekNum, daysInWeek: 1 };
   134тЖТ    } else {
   135тЖТ      currentWeek.daysInWeek++;
   136тЖТ    }
   137тЖТ  }
   138тЖТ  if (currentWeek) {
   139тЖТ    weeks.push(currentWeek);
   140тЖТ  }
   141тЖТ  return weeks;
   142тЖТ}
   143тЖТ
   144тЖТfunction getWeekNumber(date: Date): number {
   145тЖТ  const d = new Date(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()));
   146тЖТ  const dayNum = d.getUTCDay() || 7;
   147тЖТ  d.setUTCDate(d.getUTCDate() + 4 - dayNum);
   148тЖТ  const yearStart = new Date(Date.UTC(d.getUTCFullYear(), 0, 1));
   149тЖТ  return Math.ceil(((d.getTime() - yearStart.getTime()) / 86400000 + 1) / 7);
   150тЖТ}
   151тЖТ
   152тЖТfunction dateDiffDays(a: Date, b: Date): number {
   153тЖТ  return Math.floor((a.getTime() - b.getTime()) / (1000 * 60 * 60 * 24));
   154тЖТ}
   155тЖТ
   156тЖТfunction parseDate(dateStr: string): Date {
   157тЖТ  return new Date(dateStr + 'T00:00:00');
   158тЖТ}
   159тЖТ
   160тЖТfunction buildTrainIndexMap(trainOrder: string[]): Map<string, number> {
   161тЖТ  const map = new Map<string, number>();
   162тЖТ  trainOrder.forEach((id, i) => map.set(id, i));
   163тЖТ  return map;
   164тЖТ}
   165тЖТ
   166тЖТfunction buildTrainMetadata(pmBlocks: PmBlock[]): { numbers: Map<string, string>; fleets: Map<string, string> } {
   167тЖТ  const numbers = new Map<string, string>();
   168тЖТ  const fleets = new Map<string, string>();
   169тЖТ
   170тЖТ  for (const pm of pmBlocks) {
   171тЖТ    if (!numbers.has(pm.trainId)) {
   172тЖТ      numbers.set(pm.trainId, pm.trainNumber);
   173тЖТ      const code = pm.trainNumber.split('-')[0] || 'KS';
   174тЖТ      fleets.set(pm.trainId, code);
   175тЖТ    }
   176тЖТ  }
   177тЖТ
   178тЖТ  return { numbers, fleets };
   179тЖТ}
