   365тЖТ
   366тЖТ      {/* Today line */}
   367тЖТ      {todayIndex >= 0 && (
   368тЖТ        <Line
   369тЖТ          points={[
   370тЖТ            todayIndex * LAYOUT.DAY_WIDTH,
