   384тЖТinterface PmBlockRectProps {
   385тЖТ  pm: PmBlock;
   386тЖТ  x: number;
   387тЖТ  y: number;
   388тЖТ  width: number;
   389тЖТ  isSelected: boolean;
   390тЖТ  onHover?: (pm: PmBlock | null) => void;
   391тЖТ  onClick?: (pmId: string) => void;
   392тЖТ  onDragStart?: (pmId: string) => void;
   393тЖТ  onDragEnd?: (pmId: string, newDate: string) => void;
   394тЖТ  fromDate: Date;
   395тЖТ}
   396тЖТ
   397тЖТfunction PmBlockRect({
   398тЖТ  pm,
   399тЖТ  x,
   400тЖТ  y,
   401тЖТ  width,
   402тЖТ  isSelected,
   403тЖТ  onHover,
   404тЖТ  onClick,
   405тЖТ  onDragStart,
   406тЖТ  onDragEnd,
   407тЖТ  fromDate,
   408тЖТ}: PmBlockRectProps) {
   409тЖТ  const color = pm.displayColor || getPmColor(pm.status);
   410тЖТ  const finalWidth = Math.max(width, LAYOUT.MIN_PM_WIDTH);
   411тЖТ
   412тЖТ  const handleDragEnd = (e: KonvaEventObject<DragEvent>) => {
   413тЖТ    if (onDragEnd) {
   414тЖТ      const newX = e.target.x();
   415тЖТ      const dayOffset = Math.round(newX / LAYOUT.DAY_WIDTH);
   416тЖТ      const newDate = new Date(fromDate);
   417тЖТ      newDate.setDate(newDate.getDate() + dayOffset);
   418тЖТ      onDragEnd(pm.pmId, newDate.toISOString().split('T')[0]);
   419тЖТ    }
   420тЖТ  };
   421тЖТ
   422тЖТ  return (
   423тЖТ    <Group
   424тЖТ      x={x}
   425тЖТ      y={y}
   426тЖТ      draggable={!pm.isLocked}
   427тЖТ      onDragStart={() => onDragStart?.(pm.pmId)}
   428тЖТ      onDragEnd={handleDragEnd}
   429тЖТ      onMouseEnter={() => onHover?.(pm)}
   430тЖТ      onMouseLeave={() => onHover?.(null)}
   431тЖТ      onClick={() => onClick?.(pm.pmId)}
   432тЖТ    >
   433тЖТ      {/* Shadow for selected */}
   434тЖТ      {isSelected && (
   435тЖТ        <Rect
   436тЖТ          x={-2}
   437тЖТ          y={-2}
   438тЖТ          width={finalWidth + 4}
   439тЖТ          height={LAYOUT.PM_BLOCK_HEIGHT + 4}
   440тЖТ          fill="transparent"
   441тЖТ          stroke="#3b82f6"
   442тЖТ          strokeWidth={2}
   443тЖТ          cornerRadius={6}
   444тЖТ        />
   445тЖТ      )}
   446тЖТ
   447тЖТ      {/* PM block */}
   448тЖТ      <Rect
   449тЖТ        width={finalWidth}
   450тЖТ        height={LAYOUT.PM_BLOCK_HEIGHT}
   451тЖТ        fill={color}
   452тЖТ        stroke={isSelected ? '#1d4ed8' : '#00000015'}
   453тЖТ        strokeWidth={1}
   454тЖТ        cornerRadius={4}
   455тЖТ        shadowColor="#000"
   456тЖТ        shadowBlur={2}
   457тЖТ        shadowOpacity={0.1}
   458тЖТ        shadowOffsetY={1}
   459тЖТ      />
   460тЖТ
   461тЖТ      {/* Lock indicator */}
   462тЖТ      {pm.isLocked && (
   463тЖТ        <Text
   464тЖТ          x={4}
   465тЖТ          y={7}
   466тЖТ          text="ЁЯФТ"
   467тЖТ          fontSize={10}
   468тЖТ        />
   469тЖТ      )}
   470тЖТ
   471тЖТ      {/* PM code label */}
   472тЖТ      <Text
   473тЖТ        x={pm.isLocked ? 18 : 6}
   474тЖТ        y={7}
   475тЖТ        text={pm.pmCode}
   476тЖТ        fontSize={11}
   477тЖТ        fontFamily={LAYOUT.FONT_FAMILY}
   478тЖТ        fill="#ffffff"
   479тЖТ        fontStyle="bold"
   480тЖТ      />
   481тЖТ
   482тЖТ      {/* Duration label (if space) */}
   483тЖТ      {finalWidth > 50 && pm.estimatedHours && (
   484тЖТ        <Text
   485тЖТ          x={finalWidth - 30}
   486тЖТ          y={8}
   487тЖТ          text={`${pm.estimatedHours}h`}
   488тЖТ          fontSize={9}
   489тЖТ          fontFamily={LAYOUT.FONT_FAMILY}
   490тЖТ          fill="rgba(255,255,255,0.8)"
   491тЖТ        />
   492тЖТ      )}
   493тЖТ    </Group>
   494тЖТ  );
   495тЖТ}
