   497тЖТinterface ConstraintWallsLayerProps {
   498тЖТ  walls: ConstraintWall[];
   499тЖТ  trainOrder: string[];
   500тЖТ  days: DayData[];
   501тЖТ  pmBlocks: PmBlock[];
   502тЖТ  offsetX: number;
   503тЖТ}
   504тЖТ
   505тЖТfunction ConstraintWallsLayer({ walls, trainOrder, days, pmBlocks, offsetX }: ConstraintWallsLayerProps) {
   506тЖТ  const trainIndexMap = buildTrainIndexMap(trainOrder);
   507тЖТ  const pmBlockMap = new Map<string, PmBlock>();
   508тЖТ  pmBlocks.forEach((pm) => pmBlockMap.set(pm.pmId, pm));
   509тЖТ
   510тЖТ  return (
   511тЖТ    <Group x={offsetX} y={LAYOUT.HEADER_HEIGHT}>
   512тЖТ      {walls.map((wall) => {
   513тЖТ        const pm = pmBlockMap.get(wall.pmId);
   514тЖТ        if (!pm) return null;
   515тЖТ
   516тЖТ        const trainIndex = trainIndexMap.get(pm.trainId);
   517тЖТ        if (trainIndex === undefined) return null;
   518тЖТ
   519тЖТ        const dayIndex = days.findIndex((d) => d.dateStr === wall.date);
   520тЖТ        if (dayIndex < 0) return null;
   521тЖТ
   522тЖТ        const x = dayIndex * LAYOUT.DAY_WIDTH;
   523тЖТ        const y = trainIndex * LAYOUT.ROW_HEIGHT;
   524тЖТ        const color = wall.type === 'COMPLIANCE_START'
   525тЖТ          ? CONSTRAINT_COLORS.approaching
   526тЖТ          : CONSTRAINT_COLORS.hardViolation;
   527тЖТ
   528тЖТ        return (
   529тЖТ          <Line
   530тЖТ            key={`${wall.pmId}-${wall.type}`}
   531тЖТ            points={[x, y + 4, x, y + LAYOUT.ROW_HEIGHT - 4]}
   532тЖТ            stroke={color}
   533тЖТ            strokeWidth={LAYOUT.CONSTRAINT_WALL_WIDTH}
   534тЖТ            dash={[4, 2]}
   535тЖТ          />
   536тЖТ        );
   537тЖТ      })}
   538тЖТ    </Group>
   539тЖТ  );
   540тЖТ}
