   542тЖТ// =============================================================================
   543тЖТ// Main Component
   544тЖТ// =============================================================================
   545тЖТ
   546тЖТexport function TacticalGanttLayer({
   547тЖТ  data,
   548тЖТ  trainOrder,
   549тЖТ  fromDate,
   550тЖТ  toDate,
   551тЖТ  width,
   552тЖТ  height,
   553тЖТ  selectedPmIds,
   554тЖТ  onPmClick,
   555тЖТ  onPmHover,
   556тЖТ  onPmDragStart,
   557тЖТ  onPmDragEnd,
   558тЖТ  showConstraintWalls = true,
   559тЖТ  showGrid = true,
   560тЖТ}: TacticalGanttLayerProps) {
   561тЖТ  const stageRef = useRef<StageType>(null);
   562тЖТ
   563тЖТ  if (!data) {
   564тЖТ    return null;
   565тЖТ  }
   566тЖТ
   567тЖТ  // Compute derived data inline (no useMemo - pure functions)
   568тЖТ  const days = getDays(fromDate, toDate);
   569тЖТ  const weeks = getWeeks(days);
   570тЖТ  const trainIndexMap = buildTrainIndexMap(trainOrder);
   571тЖТ  const { numbers: trainNumbers, fleets: fleetCodes } = buildTrainMetadata(data.pmBlocks);
   572тЖТ  const selectedSet = new Set(selectedPmIds);
   573тЖТ
   574тЖТ  const gridOffsetX = LAYOUT.TRAIN_LABEL_WIDTH;
   575тЖТ  const contentWidth = days.length * LAYOUT.DAY_WIDTH + gridOffsetX;
   576тЖТ  const contentHeight = trainOrder.length * LAYOUT.ROW_HEIGHT + LAYOUT.HEADER_HEIGHT;
   577тЖТ
   578тЖТ  return (
   579тЖТ    <Stage
   580тЖТ      ref={stageRef}
   581тЖТ      width={width}
   582тЖТ      height={height}
   583тЖТ      style={{ backgroundColor: '#f8fafc' }}
   584тЖТ    >
   585тЖТ      {/* Background layer */}
   586тЖТ      <Layer>
   587тЖТ        <Rect width={contentWidth} height={contentHeight} fill="#ffffff" />
   588тЖТ      </Layer>
   589тЖТ
   590тЖТ      {/* Grid layer */}
   591тЖТ      {showGrid && (
   592тЖТ        <Layer>
   593тЖТ          <GanttGrid days={days} rowCount={trainOrder.length} offsetX={gridOffsetX} />
   594тЖТ        </Layer>
   595тЖТ      )}
   596тЖТ
   597тЖТ      {/* Constraint walls layer */}
   598тЖТ      {showConstraintWalls && data.constraintWalls.length > 0 && (
   599тЖТ        <Layer>
   600тЖТ          <ConstraintWallsLayer
   601тЖТ            walls={data.constraintWalls}
   602тЖТ            trainOrder={trainOrder}
   603тЖТ            days={days}
   604тЖТ            pmBlocks={data.pmBlocks}
   605тЖТ            offsetX={gridOffsetX}
   606тЖТ          />
   607тЖТ        </Layer>
   608тЖТ      )}
   609тЖТ
   610тЖТ      {/* PM blocks layer */}
   611тЖТ      <Layer>
   612тЖТ        <Group x={gridOffsetX} y={LAYOUT.HEADER_HEIGHT}>
   613тЖТ          {data.pmBlocks.map((pm) => {
   614тЖТ            const trainIndex = trainIndexMap.get(pm.trainId);
   615тЖТ            if (trainIndex === undefined) return null;
   616тЖТ
   617тЖТ            const pmDate = parseDate(pm.targetDate);
   618тЖТ            const dayOffset = dateDiffDays(pmDate, fromDate);
   619тЖТ            if (dayOffset < 0 || dayOffset >= days.length) return null;
   620тЖТ
   621тЖТ            const x = dayOffset * LAYOUT.DAY_WIDTH;
   622тЖТ            const y = trainIndex * LAYOUT.ROW_HEIGHT + LAYOUT.PM_BLOCK_MARGIN;
   623тЖТ            const blockWidth = pm.durationDays * LAYOUT.DAY_WIDTH - 4;
   624тЖТ
   625тЖТ            return (
   626тЖТ              <PmBlockRect
   627тЖТ                key={pm.pmId}
   628тЖТ                pm={pm}
   629тЖТ                x={x}
   630тЖТ                y={y}
